/**
 * @fileoverview DescriptionList barrel.
 * @module module/DescriptionList
 */
import { default as razyui } from '../index.js';
import { DescriptionListDef as DEF } from './DescriptionList.def.js';
import DescriptionList from './DescriptionList/index.js';

razyui.DescriptionList = DescriptionList;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, DescriptionList);
}

export default DescriptionList;

export const stylesheet = null;
