/**
 * @fileoverview DescriptionList view setup.
 * @module module/DescriptionList/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    root.find('.' + CLS.PAIR).each(el => {
        PART.PAIR.apply(el);
    });
    root.find('.' + CLS.TERM).each(el => {
        PART.TERM.apply(el);
    });
    root.find('.' + CLS.DETAIL).each(el => {
        PART.DETAIL.apply(el);
    });

    return {};
}
