/**
 * @fileoverview DescriptionList constants.
 * @module module/DescriptionList/constants
 */

import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:   'description-list',
    TERM:   'description-list-term',
    DETAIL: 'description-list-detail',
    PAIR:   'description-list-pair',
    DIVIDER:'description-list-divider',
});

export const DEFAULTS = Object.freeze({});

export const PART = defineParts('DescriptionList', {
    ROOT:    { class: 'dl-root', aliases: ['root', 'dl'] },
    TERM:    { class: 'dl-term', aliases: ['term', 'dt'] },
    DETAIL:  { class: 'dl-detail', aliases: ['detail', 'dd'] },
    PAIR:    { class: 'dl-pair', aliases: ['pair', 'row'] },
    DIVIDER: { class: 'dl-divider', aliases: ['divider'] },
});

PART.ROOT.jit    = 'flex flex-col [font-family:var(--dl-font-stack)]';
PART.PAIR.jit    = 'grid [grid-template-columns:var(--dl-term-width)_1fr] gap-x-[var(--dl-gap-x)] py-[var(--dl-pair-py)] [border-bottom:1px_solid_var(--dl-border)]';
PART.TERM.jit    = 'text-[var(--dl-term-font-size)] font-medium fg-[var(--dl-term-text)]';
PART.DETAIL.jit  = 'text-[var(--dl-detail-font-size)] fg-[var(--dl-detail-text)]';
PART.DIVIDER.jit = 'w-full h-[1px] bg-[var(--dl-border)]';
